#include <stdio.h>

int main() {
  int age = 25;
  float height = 1.75;
  char grade = 'A';
  printf("Age: %d years\n", age);
  printf("Height: %.2f meters\n", height);
  printf("Grade: %c\n", grade);
  return 0;
}
// Output:
// Age: 25 years
// Height: 1.75 meters
// Grade: A

